SELECT /* @SQLID=SUB020302_0102-01#Sql001 */ * FROM ( SELECT COUNT(1) OVER() AS totalCount, MUAI.BUTEN_CODE AS BUTEN_CODE, MUAI.ACCOUNT_NUMBER AS ACCOUNT_NUMBER, MUAI.NAME_KANJI AS customerNameKanji, MUAI.NAME_KANA AS customerNameKana, MUAI.COURSE AS COURSE, MUAI.CUSTOMER_ATTRIBUTE AS CUSTOMER_ATTRIBUTE, SAP.PROFILE_VALUE AS marginProfile, MUAI.INTERMEDIARY_EMP_CD AS empCode, B.BROKER_CHARGE_NAME AS brokerChargeName, MUAI.BROKER_CODE, C.BRANCH_NAME AS BROKER_NAME, MCI.BROKER_BRANCH_CODE AS branchCode, MB.BRANCH_NAME AS branchName FROM ( SELECT BROKER_CODE, INTERMEDIARY_EMP_CD, BUTEN_CODE || '-' || SUBSTR('000000' || ACCOUNT_NUMBER, -7 ) AS ACCT_ID, BUTEN_CODE, ACCOUNT_NUMBER, CUSTOMER_ATTRIBUTE AS COURSE, CUSTOMER_ATTRIBUTE, NAME_KANJI, NAME_KANA FROM MEDIATE_USER_ATTRIBUTE_INFO
BROKER_CODE = #{req.brokerCode} AND INTERMEDIARY_EMP_CD = #{req.empCode}
AND BUTEN_CODE = #{req.butenCode}
AND ACCOUNT_NUMBER = TO_NUMBER(#{req.accountNumber})
AND CUSTOMER_ATTRIBUTE NOT IN ('A') AND CUSTOMER_ATTRIBUTE IN
#{item}
AND (NAME_KANJI = #{req.customerNameKanjiKana} OR NAME_KANA = #{req.customerNameKanjiKana})
AND (NAME_KANJI LIKE #{req.customerNameKanjiKana} || '%' OR NAME_KANA LIKE #{req.customerNameKanjiKana} || '%')
AND (NAME_KANJI LIKE '%' || #{req.customerNameKanjiKana} || '%' OR NAME_KANA LIKE '%' || #{req.customerNameKanjiKana} || '%')
AND 1 = 1
AND (BROKER_CODE IN
) OR BROKER_CODE IN(
,
#{brokerChargeList.brokerCode}
)
AND ((BROKER_CODE, INTERMEDIARY_EMP_CD) IN
) OR (BROKER_CODE, INTERMEDIARY_EMP_CD) IN(
,
(#{brokerChargeList.brokerCode},#{brokerChargeList.empCode})
)
) MUAI INNER JOIN SVC_ACCT_PROFILE_IFAP SAP2 ON MUAI.ACCT_ID = SAP2.ACCT_ID AND SAP2.PROFILE_NAME = 'AccountStatus' AND SAP2.PROFILE_VALUE IN ('ACTIVE', 'SUSPENDED') LEFT JOIN SVC_ACCT_PROFILE_IFAP SAP ON MUAI.ACCT_ID = SAP.ACCT_ID AND SAP.PROFILE_NAME = 'AccountMode' AND SAP.PROFILE_VALUE = 'MARGIN' LEFT OUTER JOIN ( SELECT DISTINCT BROKER_CODE, BROKER_CHARGE_CODE, CASE BROKER_CHARGE_CODE WHEN '0000' THEN '' ELSE BROKER_CHARGE_NAME END AS BROKER_CHARGE_NAME FROM MEDIATE_CHARGE_INFO WHERE DELETE_FLG ='0' ) B ON MUAI.BROKER_CODE = B.BROKER_CODE AND MUAI.INTERMEDIARY_EMP_CD = B.BROKER_CHARGE_CODE LEFT OUTER JOIN MEDIATE_BRANCH C ON MUAI.BROKER_CODE = C.BROKER_CODE AND C.BROKER_BRANCH_KIND = '00' LEFT OUTER JOIN MEDIATE_CHARGE_INFO MCI ON MCI.BROKER_CODE = MUAI.BROKER_CODE AND MCI.BROKER_CHARGE_CODE = MUAI.INTERMEDIARY_EMP_CD AND ( SELECT COUNT(*) FROM MEDIATE_CHARGE_INFO MCI2 WHERE MUAI.BROKER_CODE = MCI2.BROKER_CODE AND MUAI.INTERMEDIARY_EMP_CD = MCI2.BROKER_CHARGE_CODE ) = 1 LEFT OUTER JOIN MEDIATE_BRANCH MB ON MB.BROKER_CODE = MUAI.BROKER_CODE AND MCI.BROKER_BRANCH_CODE =MB.BROKER_BRANCH_CODE ORDER BY COURSE, BUTEN_CODE, ACCOUNT_NUMBER )
ROWNUM <= '5000'
